/**
 * Render a single autotile pattern (0-47) onto a 2D canvas context.
 *
 * Composites 4 mini-tiles (16×16) from the autotile source image
 * into a 32×32 tile at (destX, destY) on the destination canvas.
 *
 * @param ctx   Destination canvas 2D context
 * @param img   Autotile source image (96×128 per frame, multi-frame = wider)
 * @param pattern  Pattern index 0-47
 * @param destX    X coordinate on destination
 * @param destY    Y coordinate on destination
 * @param frame    Animation frame (default 0)
 */
export function renderAutotilePattern(
  ctx: CanvasRenderingContext2D,
  img: HTMLImageElement,
  pattern: number,
  destX: number,
  destY: number,
  frame = 0,
): void {
  // For non-standard sized autotile images (< 96×128, e.g. 160×32),
  // draw a single frame-sized tile. Use the provided frame index.
  if (img.width < 96 || img.height < 128) {
    const tileW = Math.min(32, img.height > 0 ? img.height : 32);
    const tileH = tileW;
    const simpleFrameCount = Math.max(1, Math.floor(img.width / tileW));
    const simpleFrame = simpleFrameCount > 1 ? frame % simpleFrameCount : 0;
    ctx.drawImage(img, simpleFrame * tileW, 0, tileW, tileH, destX, destY, 32, 32);
    return;
  }

  const frameOffsetX = frame * 96;
  const rectBase = pattern * 4;
  const half = 16;

  for (let corner = 0; corner < 4; corner++) {
    const rect = AUTOTILE_RECTS[rectBase + corner];
    const dx = destX + (corner % 2) * half;
    const dy = destY + Math.floor(corner / 2) * half;
    ctx.drawImage(img, frameOffsetX + rect.x, rect.y, rect.w, rect.h, dx, dy, half, half);
  }
}

/**
 * Render pattern 0 (the "all neighbors match" / full center tile) to an
 * offscreen canvas and return it as a data URL.  Useful for CSS backgrounds.
 *
 * Returns null if the image is not available.
 */
export function autotilePreviewDataUrl(img: HTMLImageElement | null): string | null {
  if (!img) return null;
  const canvas = document.createElement("canvas");
  canvas.width = 32;
  canvas.height = 32;
  const ctx = canvas.getContext("2d")!;
  ctx.imageSmoothingEnabled = false;
  renderAutotilePattern(ctx, img, 0, 0, 0);
  return canvas.toDataURL();
}

// ─── Neighbor bitmask → pattern index mapping ───────────────────────────

/**
 * Neighbor bit positions for the 8-direction bitmask.
 */
export const NB_N  = 1;    // bit 0
export const NB_NE = 2;    // bit 1
export const NB_E  = 4;    // bit 2
export const NB_SE = 8;    // bit 3
export const NB_S  = 16;   // bit 4
export const NB_SW = 32;   // bit 5
export const NB_W  = 64;   // bit 6
export const NB_NW = 128;  // bit 7

/**
 * Convert an 8-bit neighbor bitmask to an RMXP autotile pattern index (0-47).
 *
 * The bitmask indicates which of the 8 neighbors share the same autotile type.
 * Diagonal gating is applied: a diagonal neighbor only counts if both of its
 * adjacent cardinal neighbors are also present.
 *
 * Pattern assignment derived from analysis of mkxp-z's AUTOTILE_RECTS table.
 */
export function bitmaskToPattern(neighbors: number): number {
  const N  = (neighbors & NB_N) !== 0;
  const NE = (neighbors & NB_NE) !== 0;
  const E  = (neighbors & NB_E) !== 0;
  const SE = (neighbors & NB_SE) !== 0;
  const S  = (neighbors & NB_S) !== 0;
  const SW = (neighbors & NB_SW) !== 0;
  const W  = (neighbors & NB_W) !== 0;
  const NW = (neighbors & NB_NW) !== 0;

  // Apply diagonal gating
  const gNE = NE && N && E;
  const gSE = SE && S && E;
  const gSW = SW && S && W;
  const gNW = NW && N && W;

  const cardCount = (N ? 1 : 0) + (E ? 1 : 0) + (S ? 1 : 0) + (W ? 1 : 0);

  if (cardCount === 4) {
    // Patterns 0-15: all 4 cardinals, diag absence bits
    return (!gNW ? 1 : 0) | (!gNE ? 2 : 0) | (!gSE ? 4 : 0) | (!gSW ? 8 : 0);
  }

  if (cardCount === 3) {
    if (!W) return 16 + (!gNE ? 1 : 0) + (!gSE ? 2 : 0);
    if (!N) return 20 + (!gSE ? 1 : 0) + (!gSW ? 2 : 0);
    if (!E) return 24 + (!gSW ? 1 : 0) + (!gNW ? 2 : 0);
    /* !S */ return 28 + (!gNW ? 1 : 0) + (!gNE ? 2 : 0);
  }

  if (cardCount === 2) {
    // Opposite pairs (no active diagonals)
    if (N && S) return 32;
    if (E && W) return 33;
    // Adjacent pairs (1 active diagonal each)
    if (S && E) return 34 + (!gSE ? 1 : 0);
    if (S && W) return 36 + (!gSW ? 1 : 0);
    if (N && W) return 38 + (!gNW ? 1 : 0);
    /* N && E */ return 40 + (!gNE ? 1 : 0);
  }

  if (cardCount === 1) {
    if (S) return 42;
    if (E) return 43;
    if (N) return 44;
    /* W */ return 45;
  }

  // No neighbors → isolated
  return 47;
}

/**
 * Precomputed 256-entry lookup table: raw bitmask → pattern index.
 */
export const BITMASK_TO_PATTERN: number[] = (() => {
  const table: number[] = new Array(256);
  for (let i = 0; i < 256; i++) {
    table[i] = bitmaskToPattern(i);
  }
  return table;
})();

/**
 * Compute the 8-bit neighbor bitmask for a tile position.
 *
 * For each of the 8 neighbors, sets the corresponding bit if the neighbor
 * is the same autotile slot. Out-of-bounds neighbors are treated as
 * NOT matching (bit = 0).
 *
 * @param tiles     Flat tile array
 * @param width     Map width
 * @param height    Map height
 * @param x         Tile X position
 * @param y         Tile Y position
 * @param layer     Tile layer (0-2)
 * @param atSlot    Autotile slot (0-6) to check for
 */
export function getNeighborBitmask(
  tiles: number[],
  width: number,
  height: number,
  x: number,
  y: number,
  layer: number,
  atSlot: number,
): number {
  let mask = 0;

  // Directions: [dx, dy, bit]
  const dirs: [number, number, number][] = [
    [0, -1, NB_N],
    [1, -1, NB_NE],
    [1, 0, NB_E],
    [1, 1, NB_SE],
    [0, 1, NB_S],
    [-1, 1, NB_SW],
    [-1, 0, NB_W],
    [-1, -1, NB_NW],
  ];

  for (const [dx, dy, bit] of dirs) {
    const nx = x + dx;
    const ny = y + dy;
    if (nx < 0 || nx >= width || ny < 0 || ny >= height) continue;

    const offset = layer * width * height + ny * width + nx;
    const neighborTile = tiles[offset];

    // Check if neighbor is the same autotile slot
    if (neighborTile >= 48 && neighborTile < 384) {
      const neighborSlot = Math.floor(neighborTile / 48) - 1;
      if (neighborSlot === atSlot) {
        mask |= bit;
      }
    }
  }

  return mask;
}
